    "No Prefect API URL provided. Please set PREFECT_API_URL to the address of a running Prefect server."
)

def _walk_annotation_for_blocks(
        cls,
        annotation: type,
        result: dict[str, type["Block"]],
    ) -> None:
        if Block.is_block_class(annotation):
            if annotation.__name__ not in result:
                result[annotation.__name__] = annotation
                # recurse into the nested block's own fields
                for nested in cls._collect_nested_block_types(annotation).items():
                    result.setdefault(nested[0], nested[1])
        if get_origin(annotation) in NestedTypes:
            for arg in get_args(annotation):
                cls._walk_annotation_for_blocks(arg, result)

async def handle_event(event: Event, fmt: str, out_file: Optional[str]) -> None:
        if fmt == "json":
            event_data = orjson.dumps(event.model_dump(), default=str).decode()
        elif fmt == "text":
            event_data = (
                f"{event.occurred.isoformat()} {event.event} {event.resource.id}"
            )
        else:
            raise ValueError(f"Unknown format: {fmt}")
        if out_file:
            async with open_file(out_file, "a") as f:  # type: ignore
                await f.write(event_data + "\n")
        else:
            print(event_data)

def uuid_validator(v: Any, field: 'ModelField') -> UUID:
    try:
        if isinstance(v, str):
            v = UUID(v)
        elif isinstance(v, (bytes, bytearray)):
            try:
                v = UUID(v.decode())
            except ValueError:
                # 16 bytes in big-endian order as the bytes argument fail
                # the above check
                v = UUID(bytes=v)
    except ValueError:
        raise errors.UUIDError()

    if not isinstance(v, UUID):
        raise errors.UUIDError()

    required_version = getattr(field.type_, '_required_version', None)
    if required_version and v.version != required_version:
        raise errors.UUIDVersionError(required_version=required_version)

    return v

def seek(self, pos, whence=0):
        if self.closed:
            raise ValueError("seek on closed file")
        try:
            pos_index = pos.__index__
        except AttributeError:
            raise TypeError(f"{pos!r} is not an integer")
        else:
            pos = pos_index()
        if whence == 0:
            if pos < 0:
                raise ValueError("negative seek position %r" % (pos,))
            self._pos = pos
        elif whence == 1:
            with self._lock:
                self._pos = max(0, self._pos + pos)
        elif whence == 2:
            with self._lock:
                self._pos = max(0, len(self._buffer) + pos)
        else:
            raise ValueError("unsupported whence value")
        return self._pos

def _walk_dir(dir, maxlevels, quiet=0):
    if quiet < 2 and isinstance(dir, os.PathLike):
        dir = os.fspath(dir)
    if not quiet:
        print('Listing {!r}...'.format(dir))
    try:
        names = os.listdir(dir)
    except OSError:
        if quiet < 2:
            print("Can't list {!r}".format(dir))
        names = []
    names.sort()
    for name in names:
        if name == '__pycache__':
            continue
        fullname = os.path.join(dir, name)
        if not os.path.isdir(fullname):
            yield fullname
        elif (maxlevels > 0 and name != os.curdir and name != os.pardir and
              os.path.isdir(fullname) and not os.path.islink(fullname)):
            yield from _walk_dir(fullname, maxlevels=maxlevels - 1,
                                 quiet=quiet)

def _find_children(self):
        with _os.scandir(self.path) as scan_iterator:
            while True:
                try:
                    entry = next(scan_iterator)
                    if entry.name == _PYCACHE:
                        continue
                    # packages
                    if entry.is_dir() and '.' not in entry.name:
                        yield entry.name
                    # files
                    if entry.is_file():
                        yield from {
                            entry.name.removesuffix(suffix)
                            for suffix, _ in self._loaders
                            if entry.name.endswith(suffix)
                        }
                except OSError:
                    pass  # ignore exceptions from next(scan_iterator) and os.DirEntry
                except StopIteration:
                    break

def _execvpe(file, args, env=None):
    if env is not None:
        exec_func = execve
        argrest = (args, env)
    else:
        exec_func = execv
        argrest = (args,)
        env = environ

    if path.dirname(file):
        exec_func(file, *argrest)
        return
    saved_exc = None
    path_list = get_exec_path(env)
    if name != 'nt':
        file = fsencode(file)
        path_list = map(fsencode, path_list)
    for dir in path_list:
        fullname = path.join(dir, file)
        try:
            exec_func(fullname, *argrest)
        except (FileNotFoundError, NotADirectoryError) as e:
            last_exc = e
        except OSError as e:
            last_exc = e
            if saved_exc is None:
                saved_exc = e
    if saved_exc is not None:
        raise saved_exc
    raise last_exc

def process_args(args, *, argv=None):
        ns = vars(args)

        fail = ns.pop('fail')
        try:
            fail = normalize_selection(fail, possible=pool)
        except UnsupportedSelectionError as exc:
            parser.error(f'invalid --fail values: {", ".join(exc.unique)}')
        else:
            if fail is None:
                fail = default

            if fail is True:
                def ignore_exc(_exc):
                    return False
            elif fail is False:
                def ignore_exc(_exc):
                    return True
            else:
                def ignore_exc(exc):
                    for err in fail:
                        if type(exc) == pool[err]:
                            return False
                    else:
                        return True
            args.ignore_exc = ignore_exc

def _repr_iterable(self, x, level, left, right, maxiter, trail=''):
        n = len(x)
        if level <= 0 and n:
            s = self.fillvalue
        else:
            newlevel = level - 1
            repr1 = self.repr1
            pieces = [repr1(elem, newlevel) for elem in islice(x, maxiter)]
            if n > maxiter:
                pieces.append(self.fillvalue)
            s = self._join(pieces, level)
            if n == 1 and trail and self.indent is None:
                right = trail + right
        return '%s%s%s' % (left, s, right)

